1471:
SELECT CAST(SUM(CASE WHEN Currency = 'EUR' THEN 1 ELSE 0 END) AS REAL) / SUM(CASE WHEN Currency = 'CZK' THEN 1 ELSE 0 END) AS eur_to_czk_ratio 
FROM customers 
WHERE Currency IN ('EUR', 'CZK');

1493:
SELECT CAST(SUM(CASE WHEN Consumption > 528.3 THEN 1 ELSE 0 END) AS REAL) * 100.0 / COUNT(*) AS percentage 
FROM yearmonth 
WHERE Date = '201202';

1498:
SELECT MAX(Consumption) as highest_monthly_consumption 
FROM yearmonth 
WHERE Date LIKE '2012%' AND Date NOT LIKE '201200%';

1352:
SELECT COUNT(*) FROM member m 
JOIN major ma ON m.link_to_major = ma.major_id 
WHERE ma.major_name = 'Business' AND m.t_shirt_size = 'Medium';

1361:
SELECT SUM(cost) as total_pizza_cost 
FROM expense 
WHERE expense_description = 'Pizza';

1378:
SELECT MAX(total_spent) as highest_budget_spent 
FROM (
    SELECT SUM(spent) as total_spent 
    FROM budget 
    GROUP BY link_to_event
);

1152:
SELECT CAST(SUM(CASE WHEN Admission = '+' THEN 1 ELSE 0 END) AS REAL) / SUM(CASE WHEN Admission = '-' THEN 1 ELSE 0 END) AS ratio 
FROM Patient 
WHERE Diagnosis = 'SLE';

1201:
SELECT CAST(SUM(CASE WHEN SEX = 'F' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(*) 
FROM Patient 
WHERE strftime('%Y', Birthday) = '1980' AND Diagnosis = 'RA';

1251:
SELECT COUNT(DISTINCT Laboratory.ID) as patient_count 
FROM Laboratory 
WHERE IGG >= 2000;

1035:
SELECT DISTINCT team_fifa_api_id 
FROM Team_Attributes 
WHERE buildUpPlaySpeed > 50 AND buildUpPlaySpeed < 60;

1039:
SELECT AVG(long_shots) as average_long_shots 
FROM Player_Attributes 
WHERE player_fifa_api_id = 163658;

1044:
SELECT player_name, birthday 
FROM Player 
WHERE substr(birthday,1,4) = '1970' AND substr(birthday,6,2) = '10';

1078:
SELECT player_name, birthday 
FROM Player 
WHERE player_name IN ('Aaron Lennon', 'Abdelaziz Barrada');

1133:
SELECT COUNT(*) FROM Player 
WHERE player_name LIKE 'Aaron%' 
AND STRFTIME('%Y', birthday) > '1990';

895:
SELECT AVG(milliseconds) as average_lap_time 
FROM lapTimes 
WHERE raceId = 2 AND driverId = 1;

537:
SELECT COUNT(*) as post_count FROM posts p 
JOIN users u ON p.OwnerUserId = u.Id 
WHERE u.DisplayName = 'csgillespie';

549:
SELECT p.Body FROM tags t 
INNER JOIN posts p ON t.ExcerptPostId = p.Id 
WHERE t.TagName = 'bayesian';

598:
SELECT 
    (CAST((SELECT COUNT(*) FROM badges WHERE Name = 'Student' AND strftime('%Y', Date) = '2010') AS REAL) / (SELECT COUNT(*) FROM badges WHERE Name = 'Student')) * 100 - 
    (CAST((SELECT COUNT(*) FROM badges WHERE Name = 'Student' AND strftime('%Y', Date) = '2011') AS REAL) / (SELECT COUNT(*) FROM badges WHERE Name = 'Student')) * 100 AS percentage_difference;

669:
SELECT MIN(CreationDate) as FirstVoteDate 
FROM votes 
WHERE UserId = (SELECT Id FROM users WHERE DisplayName = 'chl');

683:
SELECT CAST(SUM(CASE WHEN strftime('%Y', CreationDate) = '2011' AND u.Reputation > 1000 THEN 1 ELSE 0 END) AS REAL) * 100.0 / COUNT(*) AS percentage 
FROM posts p 
JOIN users u ON p.OwnerUserId = u.Id;

226:
SELECT CAST(SUM(CASE WHEN bond_type = '=' THEN 1 ELSE 0 END) AS REAL) * 100 / COUNT(bond_id) AS percentage 
FROM bond 
WHERE molecule_id = 'TR008';

228:
SELECT ROUND((SUM(CASE WHEN element = 'h' THEN 1 ELSE 0 END) * 100.0 / COUNT(atom_id)), 4) as hydrogen_percentage 
FROM atom 
WHERE molecule_id = 'TR206';

239:
SELECT COUNT(*) as connection_count 
FROM connected 
WHERE atom_id LIKE 'TR%_19' OR atom_id2 LIKE 'TR%_19';

263:
SELECT 
    COUNT(CASE WHEN a.element = 'cl' THEN 1 END) * 100.0 / COUNT(*) as percent
FROM atom a
WHERE a.molecule_id IN (
    SELECT DISTINCT molecule_id FROM bond WHERE bond_type = '-'
);

117:
SELECT 
    ROUND((SUM(CASE WHEN status = 'A' THEN amount ELSE 0 END) * 100.0 / SUM(amount)), 2) AS percentage
FROM loan;
